+            condvar: Condvar::new(),
+            mutex: Mutex::new(()),
+            idle_timeout: Duration::from_millis(10),
+            thread_name_prefix: "overflow".to_string(),
+            on_thread_start: None,
+            on_thread_stop: None,
+            thread_handles: Mutex::new(Vec::new()),
