+        // Try to spawn when already at max
+        spawn_thread_on_inner(&inner);
+        assert_eq!(inner.active_threads.load(Ordering::Relaxed), 1);
+        assert_eq!(inner.thread_handles.lock().unwrap().len(), 0);
+    }
